`,e.jsx(t.li,{children:"A tenant must never read another tenant's documents or replay another tenant's failed jobs."}),`
`,e.jsx(t.li,{children:"Ingestion failures must be inspectable and replayable without losing the original request context."}),`
`,e.jsx(t.li,{children:"Answers must be citation-grounded, or the system should refuse instead of inventing support."}),`
`,e.jsx(t.li,{children:"Operators need traces and eval reports, not just server logs."}),`
`,e.jsx(t.li,{children:"Expensive endpoints need rate limits with explicit degraded behavior when Redis is unavailable."}),`
