`,e.jsxs(t.p,{children:[e.jsx(t.strong,{children:"Refusal is a product behavior."})," If the critic cannot verify citation coverage, the finalizer returns a refusal. That is preferable to a confident answer with weak support."]}),`
`,e.jsxs(t.p,{children:[e.jsx(t.strong,{children:"DLQ replay is scoped."})," Failed ingestion jobs keep tenant and document metadata, so an operator can replay the right work without rerunning the whole corpus."]}),`
